import type { CustomEffectEntry } from '@/tools/video-editor/types';

const STORAGE_KEY = 'video-editor:draft-effects';

export function loadDraftEffects(): Record<string, string> {
  if (typeof window === 'undefined' || typeof localStorage === 'undefined') {
    return {};
  }

  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    return JSON.parse(raw) as Record<string, string>;
  } catch {
    return {};
  }
}

export function saveDraftEffect(name: string, code: string): void {
  if (typeof localStorage === 'undefined') return;

  const drafts = loadDraftEffects();
  drafts[name] = code;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(drafts));
}

export function deleteDraftEffect(name: string): void {
  if (typeof localStorage === 'undefined') return;

  const drafts = loadDraftEffects();
  delete drafts[name];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(drafts));
}

export async function promoteDraftToTimeline(
  name: string,
  saveEffect: (entry: { name: string; code: string; category?: CustomEffectEntry['category'] }) => Promise<void>,
  category?: CustomEffectEntry['category'],
): Promise<void> {
  const drafts = loadDraftEffects();
  const code = drafts[name];
  if (!code) {
    throw new Error(`No draft effect found with name "${name}"`);
  }

  await saveEffect({ name, code, category });
  deleteDraftEffect(name);
}

import { useMemo } from 'react';
import type { UseMutationOptions, UseMutationResult } from '@tanstack/react-query';
import {
  useCreateResource,
  useDeleteResource,
  useListPublicResources,
  useListResources,
  useUpdateResource,
  type EffectMetadata,
  type Resource,
} from '@/features/resources/hooks/useResources';

export type EffectCategory = EffectMetadata['category'];

export type EffectResource = EffectMetadata & {
  id: string;
  type: 'effect';
  userId?: string;
  user_id?: string;
  isPublic?: boolean;
  is_public?: boolean;
  createdAt?: string;
  created_at?: string;
};

export type EffectResourcesByCategory = Record<EffectCategory, EffectResource[]>;

const EMPTY_EFFECT_GROUPS: EffectResourcesByCategory = {
  entrance: [],
  exit: [],
  continuous: [],
};

function toEffectResource(resource: Resource): EffectResource {
  const metadata = resource.metadata as EffectMetadata;
  return {
    id: resource.id,
    type: 'effect',
    userId: resource.userId,
    user_id: resource.user_id,
    isPublic: resource.isPublic,
    is_public: resource.is_public,
    createdAt: resource.createdAt,
    created_at: resource.created_at,
    ...metadata,
  };
}

function dedupeEffectResources(resources: Resource[]): EffectResource[] {
  const deduped = new Map<string, EffectResource>();

  for (const resource of resources) {
    deduped.set(resource.id, toEffectResource(resource));
  }

  return [...deduped.values()];
}

function groupEffectResources(resources: EffectResource[]): EffectResourcesByCategory {
  return resources.reduce<EffectResourcesByCategory>((groups, resource) => {
    groups[resource.category].push(resource);
    return groups;
  }, {
    entrance: [],
    exit: [],
    continuous: [],
  });
}

export function useEffectResources(userId: string | null | undefined) {
  const privateEffectsQuery = useListResources('effect');
  const publicEffectsQuery = useListPublicResources('effect');

  const effects = useMemo(() => {
    const privateResources = userId ? privateEffectsQuery.data ?? [] : [];
    const publicResources = publicEffectsQuery.data ?? [];
    return dedupeEffectResources([...privateResources, ...publicResources]);
  }, [privateEffectsQuery.data, publicEffectsQuery.data, userId]);

  const byCategory = useMemo(() => {
    if (effects.length === 0) {
      return EMPTY_EFFECT_GROUPS;
    }

    return groupEffectResources(effects);
  }, [effects]);

  return {
    data: byCategory,
    effects,
    entrance: byCategory.entrance,
    exit: byCategory.exit,
    continuous: byCategory.continuous,
    isLoading: privateEffectsQuery.isLoading || publicEffectsQuery.isLoading,
    isFetching: privateEffectsQuery.isFetching || publicEffectsQuery.isFetching,
    error: privateEffectsQuery.error ?? publicEffectsQuery.error ?? null,
    refetch: async () => {
      const results = await Promise.all([privateEffectsQuery.refetch(), publicEffectsQuery.refetch()]);
      return results;
    },
    privateEffectsQuery,
    publicEffectsQuery,
  };
}

export function useCreateEffectResource(): Omit<
  UseMutationResult<Resource, Error, { metadata: EffectMetadata }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<Resource, Error, { metadata: EffectMetadata }, unknown>['mutate'];
  mutateAsync: (variables: { metadata: EffectMetadata }, options?: UseMutationOptions<Resource, Error, { metadata: EffectMetadata }, unknown>) => Promise<Resource>;
} {
  const mutation = useCreateResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ type: 'effect', metadata: variables.metadata }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ type: 'effect', metadata: variables.metadata }, options),
  };
}

export function useUpdateEffectResource(): Omit<
  UseMutationResult<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>['mutate'];
  mutateAsync: (variables: { id: string; metadata: EffectMetadata }, options?: UseMutationOptions<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>) => Promise<Resource>;
} {
  const mutation = useUpdateResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ id: variables.id, type: 'effect', metadata: variables.metadata }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ id: variables.id, type: 'effect', metadata: variables.metadata }, options),
  };
}

export function useDeleteEffectResource(): Omit<
  UseMutationResult<void, Error, { id: string }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<void, Error, { id: string }, unknown>['mutate'];
  mutateAsync: (variables: { id: string }, options?: UseMutationOptions<void, Error, { id: string }, unknown>) => Promise<void>;
} {
  const mutation = useDeleteResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ id: variables.id, type: 'effect' }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ id: variables.id, type: 'effect' }, options),
  };
}

import type { FC, ReactNode } from 'react';
import { secondsToFrames } from '@/tools/video-editor/lib/config-utils';
import { DynamicEffectRegistry } from '@/tools/video-editor/effects/DynamicEffectRegistry';
import { EffectErrorBoundary } from '@/tools/video-editor/effects/EffectErrorBoundary';
import { validateAndCoerceParams } from '@/tools/video-editor/effects/validateParams';
import {
  BounceEntrance,
  FadeEntrance,
  FlipEntrance,
  MeteoriteEntrance,
  PulseEntrance,
  SlideDownEntrance,
  SlideLeftEntrance,
  SlideRightEntrance,
  SlideUpEntrance,
  ZoomInEntrance,
  ZoomSpinEntrance,
  type EffectComponentProps,
} from '@/tools/video-editor/effects/entrances';
import {
  DriftEffect,
  FloatEffect,
  GlitchEffect,
  KenBurnsEffect,
  SlowZoomEffect,
} from '@/tools/video-editor/effects/continuous';
import {
  DissolveExit,
  FadeOutExit,
  FlipExit,
  ShrinkExit,
  SlideDownExit,
  ZoomOutExit,
} from '@/tools/video-editor/effects/exits';
import type { ResolvedTimelineClip } from '@/tools/video-editor/types';

export type ClipEffectComponent = FC<EffectComponentProps>;

export const entranceEffects: Record<string, ClipEffectComponent> = {
  'slide-up': SlideUpEntrance,
  'slide-down': SlideDownEntrance,
  'slide-left': SlideLeftEntrance,
  'slide-right': SlideRightEntrance,
  'zoom-in': ZoomInEntrance,
  'zoom-spin': ZoomSpinEntrance,
  pulse: PulseEntrance,
  fade: FadeEntrance,
  flip: FlipEntrance,
  bounce: BounceEntrance,
  meteorite: MeteoriteEntrance,
};

export const exitEffects: Record<string, ClipEffectComponent> = {
  'slide-down': SlideDownExit,
  'zoom-out': ZoomOutExit,
  flip: FlipExit,
  'fade-out': FadeOutExit,
  shrink: ShrinkExit,
  dissolve: DissolveExit,
};

export const continuousEffects: Record<string, ClipEffectComponent> = {
  'ken-burns': KenBurnsEffect,
  float: FloatEffect,
  glitch: GlitchEffect,
  'slow-zoom': SlowZoomEffect,
  drift: DriftEffect,
};

export const entranceEffectTypes = Object.keys(entranceEffects);
export const exitEffectTypes = Object.keys(exitEffects);
export const continuousEffectTypes = Object.keys(continuousEffects);

const allBuiltInEffects: Record<string, ClipEffectComponent> = {
  ...entranceEffects,
  ...exitEffects,
  ...continuousEffects,
};

let effectRegistry: DynamicEffectRegistry | null = null;

export function getEffectRegistry(): DynamicEffectRegistry {
  if (!effectRegistry) {
    effectRegistry = new DynamicEffectRegistry(allBuiltInEffects);
  }

  return effectRegistry;
}

export function replaceEffectRegistry(registry: DynamicEffectRegistry): DynamicEffectRegistry {
  effectRegistry = registry;
  return effectRegistry;
}

const resolveEffectName = (type: string): string => {
  return type.startsWith('custom:') ? type.slice(7) : type;
};

export const lookupEffect = (
  builtInMap: Record<string, ClipEffectComponent>,
  type: string,
): ClipEffectComponent | null => {
  const name = resolveEffectName(type);
  if (builtInMap[name]) {
    return builtInMap[name];
  }

  const registry = getEffectRegistry();
  const result = registry.get(name) ?? null;
  if (type.startsWith('custom:')) {
    console.log('[EffectLookup] type=%s resolved=%s found=%s registryAll=%o', type, name, !!result, registry.listAll());
  }
  return result;
};

export const wrapWithClipEffects = (
  content: ReactNode,
  clip: ResolvedTimelineClip,
  durationInFrames: number,
  fps: number,
): ReactNode => {
  let wrapped = content;
  const registry = getEffectRegistry();

  const continuous = clip.continuous ? lookupEffect(continuousEffects, clip.continuous.type) : null;
  if (clip.continuous && !continuous) {
    console.warn('[EffectWrap] continuous effect NOT FOUND for clip=%s type=%s', clip.id, clip.continuous.type);
  }
  if (continuous) {
    const Continuous = continuous;
    const beforeContinuous = wrapped;
    wrapped = (
      <EffectErrorBoundary effectName={clip.continuous!.type} fallback={beforeContinuous}>
        <Continuous
          durationInFrames={durationInFrames}
          intensity={clip.continuous?.intensity ?? 0.5}
          params={validateAndCoerceParams(clip.continuous?.params, registry.getSchema(clip.continuous!.type))}
        >
          {beforeContinuous}
        </Continuous>
      </EffectErrorBoundary>
    );
  }

  const entrance = clip.entrance ? lookupEffect(entranceEffects, clip.entrance.type) : null;
  if (entrance) {
    const Entrance = entrance;
    const beforeEntrance = wrapped;
    wrapped = (
      <EffectErrorBoundary effectName={clip.entrance!.type} fallback={beforeEntrance}>
        <Entrance
          durationInFrames={durationInFrames}
          effectFrames={secondsToFrames(clip.entrance?.duration ?? 0.4, fps)}
          intensity={clip.entrance?.intensity}
          params={validateAndCoerceParams(clip.entrance?.params, registry.getSchema(clip.entrance!.type))}
        >
          {beforeEntrance}
        </Entrance>
      </EffectErrorBoundary>
    );
  }

  const exit = clip.exit ? lookupEffect(exitEffects, clip.exit.type) : null;
  if (exit) {
    const Exit = exit;
    const beforeExit = wrapped;
    wrapped = (
      <EffectErrorBoundary effectName={clip.exit!.type} fallback={beforeExit}>
        <Exit
          durationInFrames={durationInFrames}
          effectFrames={secondsToFrames(clip.exit?.duration ?? 0.4, fps)}
          intensity={clip.exit?.intensity}
          params={validateAndCoerceParams(clip.exit?.params, registry.getSchema(clip.exit!.type))}
        >
          {beforeExit}
        </Exit>
      </EffectErrorBoundary>
    );
  }

  return wrapped;
};

import type { FC } from 'react';
import type { EffectComponentProps } from '@/tools/video-editor/effects/entrances';
import { compileEffect, compileEffectAsync } from '@/tools/video-editor/effects/compileEffect';
import type { ParameterSchema } from '@/tools/video-editor/types';

type DynamicEffectRecord = {
  component: FC<EffectComponentProps>;
  code: string;
  schema?: ParameterSchema;
};

export class DynamicEffectRegistry {
  private builtIn: Record<string, FC<EffectComponentProps>>;
  private dynamic: Record<string, DynamicEffectRecord> = {};
  private _version = 0;
  private _batchDepth = 0;
  private _pendingNotify = false;
  private _listeners = new Set<() => void>();

  constructor(builtIn: Record<string, FC<EffectComponentProps>>) {
    this.builtIn = { ...builtIn };
  }

  subscribe = (listener: () => void): (() => void) => {
    this._listeners.add(listener);
    return () => this._listeners.delete(listener);
  };

  getSnapshot = (): number => this._version;

  async batch(fn: () => void | Promise<void>): Promise<void> {
    this._batchDepth += 1;
    try {
      await fn();
    } finally {
      this._batchDepth -= 1;
      if (this._batchDepth === 0 && this._pendingNotify) {
        this._pendingNotify = false;
        this._notify();
      }
    }
  }

  register(name: string, code: string, schema?: ParameterSchema): void {
    const normalized = this.normalizeName(name);
    const existing = this.dynamic[normalized];
    if (existing?.code === code && existing.schema === schema) return;
    const component = compileEffect(code);
    this.dynamic[normalized] = { component, code, schema };
    this._notify();
  }

  async registerAsync(name: string, code: string, schema?: ParameterSchema): Promise<void> {
    const normalized = this.normalizeName(name);
    const existing = this.dynamic[normalized];
    if (existing?.code === code && existing.schema === schema) return;
    const component = await compileEffectAsync(code);
    this.dynamic[normalized] = { component, code, schema };
    this._notify();
  }

  unregister(name: string): void {
    const normalized = this.normalizeName(name);
    if (!(normalized in this.dynamic)) return;
    delete this.dynamic[normalized];
    this._notify();
  }

  get(name: string): FC<EffectComponentProps> | undefined {
    const normalized = this.normalizeName(name);
    return this.builtIn[normalized] ?? this.dynamic[normalized]?.component;
  }

  getCode(name: string): string | undefined {
    return this.dynamic[this.normalizeName(name)]?.code;
  }

  getSchema(name: string): ParameterSchema | undefined {
    return this.dynamic[this.normalizeName(name)]?.schema;
  }

  listAll(): string[] {
    return [...new Set([...Object.keys(this.builtIn), ...Object.keys(this.dynamic)])];
  }

  isDynamic(name: string): boolean {
    const normalized = this.normalizeName(name);
    return normalized in this.dynamic && !(normalized in this.builtIn);
  }

  getAllDynamicCode(): Record<string, string> {
    return Object.fromEntries(
